import heapq

class Solution:
    def kWeakestRows(self, mat: list[list[int]], k: int) -> list[int]:
        rows_data = []
        for i, row in enumerate(mat):
            strength = sum(row)
            rows_data.append((strength, i))

        weakest_rows_tuples = heapq.nsmallest(k, rows_data)

        result = [index for strength, index in weakest_rows_tuples]

        return result
